def parse_kv_list(items: Optional[List[str]]) -> Dict[str, str]:
    cfg: Dict[str, str] = {}
    if not items:
        return cfg
    for item in items:
        if "=" not in item:
            raise ValueError(f"Invalid key=value item: {item}")
        k, v = item.split("=", 1)
        k = k.strip()
        v = v.strip()
        if not k:
            raise ValueError(f"Invalid key in item: {item}")
        cfg[k] = v
    return cfg


def parse_topics(topics: Optional[List[str]], topics_csv: Optional[str], topics_file: Optional[str]) -> List[str]:
    result: List[str] = []
    if topics:
        result.extend(topics)
    if topics_csv:
        result.extend([t.strip() for t in topics_csv.split(",") if t.strip()])
    if topics_file:
        with open(topics_file, "r", encoding="utf-8") as f:
            for line in f:
                t = line.strip()
                if t and not t.startswith("#"):
                    result.append(t)
    dedup = []
    seen = set()
    for t in result:
        if t not in seen:
            seen.add(t)
            dedup.append(t)
    return dedup


def parse_json_file(path: str) -> dict:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def wait_for_topics(admin: KafkaAdminClient, topics: List[str], timeout_s: float = 30.0, interval_s: float = 1.0) -> None:
    deadline = time.time() + timeout_s
    remaining = set(topics)
    while remaining and time.time() < deadline:
        try:
            existing = set(admin.list_topics())
            remaining = remaining - existing
        except KafkaError:
            pass
        if remaining:
            time.sleep(interval_s)
    if remaining:
        raise TimeoutError(f"Timed out waiting for topics to appear: {sorted(remaining)}")


def create_topics(
    admin: KafkaAdminClient,
    topics: List[str],
    partitions: int,
    replication_factor: int,
    configs: Dict[str, str],
    validate_only: bool = False,
    timeout_ms: int = 30000,
) -> Tuple[List[str], List[Tuple[str, str]]]:
    created: List[str] = []
    errors: List[Tuple[str, str]] = []

    new_topics = []
    for t in topics:
        new_topics.append(
            NewTopic(
                name=t,
                num_partitions=partitions,
                replication_factor=replication_factor,
                topic_configs=configs if configs else None,
            )
        )

    if validate_only:
        for t in topics:
            created.append(t)
        return created, errors

    try:
        admin.create_topics(new_topics=new_topics, validate_only=False, timeout_ms=timeout_ms)
        created.extend(topics)
    except TopicAlreadyExistsError:
        for t in topics:
            errors.append((t, "TopicAlreadyExists"))
    except KafkaError as e:
        errors.append(("*", f"{type(e).__name__}: {e}"))

    return created, errors


