def describe_topics(admin: KafkaAdminClient, topics: List[str]) -> dict:
    out = {"topics": {}}
    try:
        md = admin._client.cluster
        admin._client.poll(timeout_ms=5000)
        md.request_update()
        admin._client.poll(timeout_ms=5000)
    except Exception:
        pass

    try:
        topic_md = admin._client.cluster.topics()
        for t in topics:
            if t not in topic_md:
                out["topics"][t] = {"error": "UnknownTopicOrPartition"}
                continue
            partitions = admin._client.cluster.partitions_for_topic(t) or set()
            part_info = {}
            for p in sorted(partitions):
                leader = admin._client.cluster.leader_for_partition((t, p))
                replicas = admin._client.cluster.replicas_for_partition((t, p))
                isr = admin._client.cluster.isr_for_partition((t, p))
                part_info[str(p)] = {
                    "leader": leader,
                    "replicas": sorted(list(replicas)) if replicas else None,
                    "isr": sorted(list(isr)) if isr else None,
                }
            out["topics"][t] = {"partitions": part_info}
    except Exception as e:
        out["error"] = f"{type(e).__name__}: {e}"
    return out


